//go:build vectors

package ingest

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"log/slog"
	"sync"

	"github.com/a<HOME>/agentic-rag-mcp/internal/domain"

	"github.com/<HOME>/bleve/v2"
	"github.com/<HOME>/bleve/v2/mapping"
)

// Indexer manages the bleve index for knowledge chunks.
type Indexer struct {
	mu        sync.RWMutex
	index     bleve.Index
	path      string
	dims      int
	hashes    map[string]string // path -> contentHash
	docChunks map[string]int    // documentSlug -> chunk count
}

// bleveChunk is the document stored in bleve.
type bleveChunk struct {
	QualifiedID  string    `json:"qualifiedId"`
	SectionID    string    `json:"sectionId"`
	DocumentSlug string    `json:"documentSlug"`
	Title        string    `json:"title"`
	Content      string    `json:"content"`
	Scope        string    `json:"scope"`
	Kind         string    `json:"kind"`
	Tags         []string  `json:"tags"`
	Position     int       `json:"position"`
	Vector       []float32 `json:"_vector"`
}

// NewIndexer creates or opens a bleve index at the given path.
func NewIndexer(path string, dims int) (*Indexer, error) {
	idx, err := bleve.Open(path)
	if err != nil {
		// Create new index
		idx, err = createIndex(path, dims)
		if err != nil {
			return nil, fmt.Errorf("creating index: %w", err)
		}
	}

	return &Indexer{
		index:     idx,
		path:      path,
		dims:      dims,
		hashes:    make(map[string]string),
		docChunks: make(map[string]int),
	}, nil
}

// NewIndexerWithIndex creates an Indexer from an existing bleve.Index (for testing).
func NewIndexerWithIndex(idx bleve.Index, path string, dims int) *Indexer {
	return &Indexer{
		index:     idx,
		path:      path,
		dims:      dims,
		hashes:    make(map[string]string),
		docChunks: make(map[string]int),
	}
}

func createIndex(path string, dims int) (bleve.Index, error) {
	// Build index mapping with vector field
	indexMapping := bleve.NewIndexMapping()

	chunkMapping := bleve.NewDocumentMapping()

	// Text fields for BM25
	textFieldMapping := bleve.NewTextFieldMapping()
	textFieldMapping.Analyzer = "standard"
	chunkMapping.AddFieldMappingsAt("content", textFieldMapping)
	chunkMapping.AddFieldMappingsAt("title", textFieldMapping)

	// Keyword fields for filtering
	keywordFieldMapping := bleve.NewKeywordFieldMapping()
	chunkMapping.AddFieldMappingsAt("scope", keywordFieldMapping)
	chunkMapping.AddFieldMappingsAt("kind", keywordFieldMapping)
	chunkMapping.AddFieldMappingsAt("documentSlug", keywordFieldMapping)
	chunkMapping.AddFieldMappingsAt("sectionId", keywordFieldMapping)
	chunkMapping.AddFieldMappingsAt("qualifiedId", keywordFieldMapping)
	chunkMapping.AddFieldMappingsAt("tags", keywordFieldMapping)

	// Numeric field for position
	numericFieldMapping := bleve.NewNumericFieldMapping()
	chunkMapping.AddFieldMappingsAt("position", numericFieldMapping)

	// Vector field for KNN search
	vectorFieldMapping := mapping.NewVectorFieldMapping()
	vectorFieldMapping.Dims = dims
	vectorFieldMapping.Similarity = "cosine"
	chunkMapping.AddFieldMappingsAt("_vector", vectorFieldMapping)

	indexMapping.AddDocumentMapping("chunk", chunkMapping)
	indexMapping.DefaultMapping = chunkMapping

	return bleve.New(path, indexMapping)
}

// StoreChunks writes chunks to the index.
func (ix *Indexer) StoreChunks(chunks []domain.Chunk) error {
	ix.mu.Lock()
	defer ix.mu.Unlock()

	batch := ix.index.NewBatch()
	for _, c := range chunks {
		doc := bleveChunk{
			QualifiedID:  c.QualifiedID,
			SectionID:    c.SectionID,
			DocumentSlug: c.DocumentSlug,
			Title:        c.Title,
			Content:      c.Content,
			Scope:        c.Scope,
			Kind:         c.Kind,
			Tags:         c.Tags,
			Position:     c.Position,
			Vector:       c.Vector,
		}
		if err := batch.Index(c.QualifiedID, doc); err != nil {
			return fmt.Errorf("indexing chunk %s: %w", c.QualifiedID, err)
		}
	}

	if err := ix.index.Batch(batch); err != nil {
		return fmt.Errorf("batch write: %w", err)
	}

	// Update chunk counts
	if len(chunks) > 0 {
		slug := chunks[0].DocumentSlug
		ix.docChunks[slug] = len(chunks)
	}

	return nil
}

// RemoveDocument removes all chunks for a given document slug from the index.
func (ix *Indexer) RemoveDocument(slug string) error {
	ix.mu.Lock()
	defer ix.mu.Unlock()

	// Search for all chunks with this document slug
	query := bleve.NewTermQuery(slug)
	query.SetField("documentSlug")
	req := bleve.NewSearchRequest(query)
	req.Size = 10000 // reasonable upper bound
	req.Fields = []string{"qualifiedId"}

	results, err := ix.index.Search(req)
	if err != nil {
		return fmt.Errorf("searching for document chunks: %w", err)
	}

	batch := ix.index.NewBatch()
	for _, hit := range results.Hits {
		batch.Delete(hit.ID)
	}

	if err := ix.index.Batch(batch); err != nil {
		return fmt.Errorf("batch delete: %w", err)
	}

	delete(ix.docChunks, slug)

	slog.Info("removed document chunks", "slug", slug, "count", len(results.Hits))
	return nil
}

// HasChanged checks if a document's content has changed since last indexing.
func (ix *Indexer) HasChanged(path string, content []byte) bool {
	ix.mu.RLock()
	defer ix.mu.RUnlock()

	hash := contentHash(content)
	stored, exists := ix.hashes[path]
	return !exists || stored != hash
}

// RecordHash stores the content hash for a document path.
func (ix *Indexer) RecordHash(path string, content []byte) {
	ix.mu.Lock()
	defer ix.mu.Unlock()

	ix.hashes[path] = contentHash(content)
}

// GetHash returns the stored hash for a path.
func (ix *Indexer) GetHash(path string) (string, bool) {
	ix.mu.RLock()
	defer ix.mu.RUnlock()

	h, ok := ix.hashes[path]
	return h, ok
}

// IndexedPaths returns all paths that have been indexed.
func (ix *Indexer) IndexedPaths() map[string]string {
	ix.mu.RLock()
	defer ix.mu.RUnlock()

	result := make(map[string]string, len(ix.hashes))
	for k, v := range ix.hashes {
		result[k] = v
	}
	return result
}

// BleveIndex returns the underlying bleve.Index for search operations.
func (ix *Indexer) BleveIndex() bleve.Index {
	ix.mu.RLock()
	defer ix.mu.RUnlock()

	return ix.index
}

// Path returns the filesystem path of the index.
func (ix *Indexer) Path() string {
	return ix.path
}

// Dims returns the vector dimensions.
func (ix *Indexer) Dims() int {
	return ix.dims
}

// DocCount returns the number of indexed documents.
func (ix *Indexer) DocCount() int {
	ix.mu.RLock()
	defer ix.mu.RUnlock()

	return len(ix.hashes)
}

// ChunkCount returns the total number of indexed chunks.
func (ix *Indexer) ChunkCount() int {
	ix.mu.RLock()
	defer ix.mu.RUnlock()

	count, _ := ix.index.DocCount()
	return int(count)
}

// Close closes the bleve index.
func (ix *Indexer) Close() error {
	ix.mu.Lock()
	defer ix.mu.Unlock()

	return ix.index.Close()
}

// SwapIndex atomically replaces the current index with a new one.
func (ix *Indexer) SwapIndex(newIndex bleve.Index, newHashes map[string]string) {
	ix.mu.Lock()
	defer ix.mu.Unlock()

	old := ix.index
	ix.index = newIndex
	ix.hashes = newHashes
	ix.docChunks = make(map[string]int)

	// Close old index in background
	go func() {
		if err := old.Close(); err != nil {
			slog.Error("closing old index after swap", "error", err)
		}
	}()
}

// CreateTempIndex creates a new empty index at a temporary path for atomic swap.
func CreateTempIndex(path string, dims int) (bleve.Index, error) {
	return createIndex(path, dims)
}

func contentHash(data []byte) string {
	h := sha256.Sum256(data)
	return hex.EncodeToString(h[:])
}
